/**
 * Shared-prefix KV reuse — `Pipeline.prepareSharedPrefixPrefill`.
 *
 * Proves the token-axis shared-prefix path wired for the sovereign-infer
 * coordinator:
 *   1. First request for a shared prefix MISSES the shared-prefix Amplituhedron
 *      key → full prefill runs → a shared-prefix capture (at prefix_len =
 *      sharedLen) is scheduled in addition to the full-prompt capture.
 *   2. A SIBLING request (same shared prefix, DIFFERENT suffix) HITS the
 *      shared-prefix key → only the SUFFIX tokens are forwarded (the shared
 *      prefix is NOT re-prefilled). The forward count is the measurable win.
 *
 * The mock station mirrors the optional `amplituhedronReplay` /
 * `amplituhedronCapture` duck-typed surface. Unlike the live worker-node1
 * handlers (which currently speak JSON and never return tensors — see the
 * report), this mock implements the binary-equivalent semantics the host
 * Pipeline expects, so it exercises the HIT branch the wire defect blocks live.
 */

import { describe, expect, it } from 'vitest';

import { Pipeline, prefixHashU64 } from '../pipeline';
import type { IStation } from '../types';

const HIDDEN_DIM = 4;
const VOCAB = 8;

interface Counters {
  forwards: number;
  embeds: number;
  lmHeads: number;
  replays: number;
  captures: number;
  /** seqLen of every forward, so we can prove only the suffix was prefilled. */
  forwardSeqLens: number[];
}

interface CachedVolume {
  prefixHash: string;
  prefixLen: number;
  tailResidual: Float32Array;
}

function buildStation(opts: {
  startLayer: number;
  endLayer: number;
  role: 'entry' | 'mid' | 'exit';
  lmHeadArgmax?: number;
}): { station: IStation; counters: Counters; cache: CachedVolume[] } {
  const counters: Counters = {
    forwards: 0,
    embeds: 0,
    lmHeads: 0,
    replays: 0,
    captures: 0,
    forwardSeqLens: [],
  };
  const cache: CachedVolume[] = [];
  const synthTail = (prefixLen: number): Float32Array => {
    const out = new Float32Array(HIDDEN_DIM);
    for (let i = 0; i < HIDDEN_DIM; i++) out[i] = (prefixLen + i) * 0.001;
    return out;
  };

  const station = {
    startLayer: opts.startLayer,
    endLayer: opts.endLayer,
    role: opts.role,
    maxBatchSize: 8,

    async embed({ tokens }: { tokens: Uint32Array; startPos: number }) {
      counters.embeds++;
      const out = new Float32Array(tokens.length * HIDDEN_DIM);
      for (let i = 0; i < out.length; i++) out[i] = (i + 1) * 0.001;
      return out;
    },
    async forward({ residual, sequenceLength }: { residual: Float32Array; startPos: number; sequenceLength: number }) {
      counters.forwards++;
      counters.forwardSeqLens.push(sequenceLength);
      const out = new Float32Array(sequenceLength * HIDDEN_DIM);
      for (let i = 0; i < out.length; i++) out[i] = (residual[i] ?? 0) + 0.01;
      return { residual: out };
    },
    async lmHead() {
      counters.lmHeads++;
      const out = new Float32Array(VOCAB);
      out[opts.lmHeadArgmax ?? 3] = 1;
      return out;
    },
    async cobordismEmbed() { throw new Error('not used'); },
    async cobordismLmHead() { throw new Error('not used'); },
    async bizarroForward() { return null; },

    async amplituhedronReplay({ prefixHash, prefixLen }: { prefixHash: string; prefixLen: number }) {
      counters.replays++;
      const hit = cache.find((v) => v.prefixHash === prefixHash && v.prefixLen === prefixLen);
      if (!hit) return { hit: false };
      // On a hit the real station reseeds set_kv_slab for [0, prefixLen) and
      // returns the tail residual; the mock just returns the tail.
      return { hit: true, tailResidual: hit.tailResidual };
    },
    async amplituhedronCapture({ prefixHash, prefixLen }: { prefixHash: string; prefixLen: number; tailResidual?: Float32Array }) {
      counters.captures++;
      cache.push({ prefixHash, prefixLen, tailResidual: synthTail(prefixLen) });
    },
  } as unknown as IStation;

  return { station, counters, cache };
}

function makePipeline(stations: IStation[]): Pipeline {
  return new Pipeline({ stations, hiddenDim: HIDDEN_DIM, vocabSize: VOCAB, stopTokens: [] });
}

describe('Pipeline.prepareSharedPrefixPrefill (shared-prefix KV reuse)', () => {
  const SHARED = [7, 11, 13, 17]; // 4 shared tokens
  const sharedLen = SHARED.length;

  it('captures the shared-prefix key on a miss and prefills only the suffix on a sibling hit', async () => {
    const s0 = buildStation({ startLayer: 0, endLayer: 4, role: 'entry' });
    const s1 = buildStation({ startLayer: 4, endLayer: 8, role: 'exit', lmHeadArgmax: 5 });
    const pipe = makePipeline([s0.station, s1.station]);

    const promptA = new Uint32Array([...SHARED, 101, 103]); // 6 tokens
    const promptB = new Uint32Array([...SHARED, 211, 223]); // sibling: same prefix, diff suffix

    // ── Call A: shared-prefix MISS → full prefill of all 6 tokens, then
    //   full-prompt capture + shared-prefix capture (prefix_len = sharedLen).
    const prepA = await pipe.prepareSharedPrefixPrefill({ promptTokens: promptA, sharedPrefixLen: sharedLen });
    expect(prepA.telemetry.source).toBe('amplituhedron-miss'); // full-prompt path
    await new Promise((r) => setTimeout(r, 0)); // flush fire-and-forget captures

    // Two distinct keys captured per station: full-prompt (len 6) + shared (len 4).
    const sharedHash = await prefixHashU64(promptA.subarray(0, sharedLen));
    expect(s0.cache.some((v) => v.prefixHash === sharedHash && v.prefixLen === sharedLen)).toBe(true);
    expect(s1.cache.some((v) => v.prefixHash === sharedHash && v.prefixLen === sharedLen)).toBe(true);

    const s0ForwardsBefore = s0.counters.forwards;
    const s1ForwardsBefore = s1.counters.forwards;
    const s0EmbedsBefore = s0.counters.embeds;

    // ── Call B: sibling suffix. Shared-prefix replay HITS → only the 2 suffix
    //   tokens are forwarded (NOT all 6). This is the reuse win.
    const prepB = await pipe.prepareSharedPrefixPrefill({ promptTokens: promptB, sharedPrefixLen: sharedLen });
    expect(prepB.telemetry.source).toBe('amplituhedron-partial'); // shared-prefix HIT
    expect(prepB.telemetry.prefixLen).toBe(sharedLen);

    // The suffix prefill embeds only the 2 suffix tokens and forwards seqLen=2,
    // never the full 6-token prompt. Prove via the seqLens recorded since B started.
    const s0NewForwards = s0.counters.forwardSeqLens.slice(s0ForwardsBefore);
    const totalForwardedTokens = s0NewForwards.reduce((a, b) => a + b, 0);
    expect(totalForwardedTokens).toBe(promptB.length - sharedLen); // == 2, the suffix only
    expect(totalForwardedTokens).toBeLessThan(promptB.length);     // strictly fewer than full prefill

    // Both stations did forward the suffix (decode seed needs the suffix residual).
    expect(s1.counters.forwards).toBeGreaterThan(s1ForwardsBefore);
    // No full-prompt embed on the hit path (suffix-only embed, fewer tokens).
    expect(s0.counters.embeds).toBe(s0EmbedsBefore + 1); // one suffix embed
  });

  it('falls back to the full-prompt path when sharedPrefixLen is 0 or >= prompt length', async () => {
    const s0 = buildStation({ startLayer: 0, endLayer: 4, role: 'entry' });
    const s1 = buildStation({ startLayer: 4, endLayer: 8, role: 'exit', lmHeadArgmax: 5 });
    const pipe = makePipeline([s0.station, s1.station]);
    const prompt = new Uint32Array([...SHARED, 101, 103]);

    const zero = await pipe.prepareSharedPrefixPrefill({ promptTokens: prompt, sharedPrefixLen: 0 });
    expect(zero.telemetry.source).toBe('amplituhedron-miss'); // == plain preparePrefill miss

    const whole = await pipe.prepareSharedPrefixPrefill({ promptTokens: prompt, sharedPrefixLen: prompt.length });
    // whole-prompt shared prefix has no suffix to seed decode → defers to full path
    expect(whole.telemetry.prefixLen).toBe(prompt.length);
  });
});
